impl<R: TemporaryPermissionProjectionRepository> TemporaryPermissionEventHandler for TemporaryPermissionProjector<R> {

    async fn on_created(&self, event: TemporaryPermissionCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = TemporaryPermissionProjection::new(
            event.id,
            event.user_id,
            event.permission_id,
            event.granted_by,
            event.granted_at,
            event.expires_at,
            event.revoked_at,
            event.revoked_by,
            event.reason,
            event.notified_before_expiry,
            event.status,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: TemporaryPermissionUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.permission_id = event.permission_id;
            projection.granted_by = event.granted_by;
            projection.granted_at = event.granted_at;
            projection.expires_at = event.expires_at;
            projection.revoked_at = event.revoked_at;
            projection.revoked_by = event.revoked_by;
            projection.reason = event.reason;
            projection.notified_before_expiry = event.notified_before_expiry;
            projection.status = event.status;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: TemporaryPermissionDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

